import axios from 'axios';

export const signup = async ({username, password, email}) => {
    try{
        const request = await axios.post("/auth/signup",
            {username, password, email}
        );
        console.log(request.data);
    }catch(err){
        console.log(err);
    }
}

module.exports = signup;
